import{_ as a,a as t}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as i,o,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Aggiungere un canale Hugging Face","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/huggingface.md","filePath":"it-IT/upload/huggingface.md","lastUpdated":1781962217000}'),s={name:"it-IT/upload/huggingface.md"};function c(l,e,d,g,p,u){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="aggiungere-un-canale-hugging-face" tabindex="-1">Aggiungere un canale Hugging Face <a class="header-anchor" href="#aggiungere-un-canale-hugging-face" aria-label="Permalink to &quot;Aggiungere un canale Hugging Face&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><p>Servono solo tre cose:</p><table tabindex="0"><thead><tr><th>Requisito</th><th>Scopo</th></tr></thead><tbody><tr><td>Account Hugging Face</td><td>Per generare un access token e possedere il repository.</td></tr><tr><td>Hugging Face User Access Token</td><td>Permette a ImgBed di usare l&#39;API Hugging Face, creare repository e caricare file.</td></tr><tr><td>Nome repository</td><td>Puoi inserire anche solo il nome, per esempio <code>image</code>.</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="passaggio-1-accedi-a-hugging-face-e-crea-un-access-token" tabindex="-1">Passaggio 1: accedi a Hugging Face e crea un Access Token <a class="header-anchor" href="#passaggio-1-accedi-a-hugging-face-e-crea-un-access-token" aria-label="Permalink to &quot;Passaggio 1: accedi a Hugging Face e crea un Access Token&quot;">​</a></h3><ol><li>Accedi a Hugging Face.</li><li>Clicca sull&#39;avatar in alto a destra e apri <code>Settings</code>.</li><li>Apri <code>Access Tokens</code> dalla barra laterale.</li><li>Crea un nuovo token.</li><li>Dai al token un nome riconoscibile.</li><li>Seleziona il permesso <code>write</code>.</li><li>Copia e salva subito il token appena viene creato.</li></ol><p><img src="'+a+'" alt="Crea token" loading="lazy"></p><h2 id="passaggio-2-compila-il-canale-hugging-face-in-imgbed" tabindex="-1">Passaggio 2: compila il canale Hugging Face in ImgBed <a class="header-anchor" href="#passaggio-2-compila-il-canale-hugging-face-in-imgbed" aria-label="Permalink to &quot;Passaggio 2: compila il canale Hugging Face in ImgBed&quot;">​</a></h2><p>Dopo aver scelto <code>Hugging Face</code> nelle Impostazioni di caricamento, compila:</p><table tabindex="0"><thead><tr><th>Campo UI</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Nome canale</td><td>Un nome a tua scelta, per esempio <code>hf-primary</code>.</td></tr><tr><td>Nome repository</td><td>Un nome breve come <code>image</code>, oppure un percorso completo come <code>username/image</code>.</td></tr><tr><td>Access Token</td><td>Lo User Access Token Hugging Face appena creato.</td></tr><tr><td>Repository privato</td><td>Attiva o disattiva in base alle tue esigenze.</td></tr><tr><td>Nota</td><td>Opzionale, per esempio <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+t+`" alt="Aggiungi canale" loading="lazy"></p><h2 id="passaggio-3-salva-il-canale" tabindex="-1">Passaggio 3: salva il canale <a class="header-anchor" href="#passaggio-3-salva-il-canale" aria-label="Permalink to &quot;Passaggio 3: salva il canale&quot;">​</a></h2><p>Dopo aver compilato i campi, salva.</p><p>Il sistema gestisce automaticamente questi dettagli:</p><table tabindex="0"><thead><tr><th>Comportamento</th><th>Descrizione</th></tr></thead><tbody><tr><td>Nome repository breve</td><td>ImgBed identifica l&#39;account Hugging Face corrente e lo trasforma in un percorso completo.</td></tr><tr><td>Percorso repository completo</td><td>ImgBed usa <code>username/repository</code> esattamente come inserito.</td></tr><tr><td>Controllo repository</td><td>Se usi il percorso dell&#39;account personale corrente, ImgBed prova a creare il repository se non esiste. Se inserisci manualmente un percorso completo, lo usa direttamente.</td></tr><tr><td>Tipo repository</td><td>Questo canale usa un repository <code>dataset</code>.</td></tr><tr><td>Pubblico/privato</td><td>La visibilità del repository viene sincronizzata con l&#39;interruttore corrente.</td></tr></tbody></table><h2 id="checklist-rapida" tabindex="-1">Checklist rapida <a class="header-anchor" href="#checklist-rapida" aria-label="Permalink to &quot;Checklist rapida&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Accedi a Hugging Face</span></span>
<span class="line"><span>-&gt; Crea un Access Token</span></span>
<span class="line"><span>-&gt; Seleziona permesso write</span></span>
<span class="line"><span>-&gt; Torna in ImgBed e inserisci token e nome repository</span></span>
<span class="line"><span>-&gt; Salva</span></span>
<span class="line"><span>-&gt; Se inserisci solo il nome repo, ImgBed aggiunge automaticamente lo username corrente</span></span>
<span class="line"><span>-&gt; Se inserisci username/repo, ImgBed lo usa così com&#39;è</span></span>
<span class="line"><span>-&gt; ImgBed controlla o crea il repository dataset</span></span>
<span class="line"><span>-&gt; Carica un&#39;immagine di prova</span></span></code></pre></div>`,18)])])}const f=i(s,[["render",c]]);export{b as __pageData,f as default};
